import{_ as a,o as t,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Ad Partner Integration Guide","description":"","frontmatter":{"title":"Ad Partner Integration Guide","slug":"ad-partner-integration-guide"},"headers":[],"relativePath":"marketer-hub/ad-partner-integration-guide.md","filePath":"marketer-hub/ad-partner-integration-guide.md"}'),o={name:"marketer-hub/ad-partner-integration-guide.md"};function i(s,e,d,l,h,c){return t(),r("div",null,[...e[0]||(e[0]=[n('<p>This guide will walk you through connecting your ad partner in Branch to track campaign performance.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable your ad partner, you need to have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Added the Performance <a href="./packaging.html">product</a> to your Branch account.</p></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li></ol><h2 id="_1-enable-ad-partner" tabindex="-1">1. Enable Ad Partner <a class="header-anchor" href="#_1-enable-ad-partner" aria-label="Permalink to &quot;1. Enable Ad Partner&quot;">​</a></h2><ol><li>Visit the <a href="https://dashboard.branch.io/ads" target="_blank" rel="noreferrer">Ads page</a> on the Branch dashboard.</li><li>Select <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Partner Management</a> from the sidebar.</li><li>Search for your <strong>Ad Partner</strong>.</li><li>Select Ad Partner Name and hit <strong>Save &amp; Enable</strong>.</li></ol><h2 id="_2-provide-account-credentials" tabindex="-1">2. Provide Account Credentials <a class="header-anchor" href="#_2-provide-account-credentials" aria-label="Permalink to &quot;2. Provide Account Credentials&quot;">​</a></h2><p>Not all integrations require providing account credentials.</p><p>When prompted to, enter any credentials that may be required, and click <strong>Save and Enable</strong> in the bottom right-hand corner.</p><p>If you do not know your account credentials for said partner, please ask your ad partner for this information.</p><h2 id="_3-enable-postbacks" tabindex="-1">3. Enable Postbacks <a class="header-anchor" href="#_3-enable-postbacks" aria-label="Permalink to &quot;3. Enable Postbacks&quot;">​</a></h2><p>When a conversion/event attributed to an ad campaign occurs, Branch notifies the Ad partner of these events via <strong>postbacks</strong> which are turned on when you enable any Ads integrated partner (Postback Config tab of the ad partner)</p><p>Basic postbacks will automatically be activated for events like <strong>INSTALL</strong> and <strong>PURCHASE</strong> when you enable your ad partner.</p><p>For a more detailed guide on configuring Postbacks, view our guides:</p><ul><li><a href="./basic-postback-configuration.html">Basic Postback Configuration</a></li><li><a href="./advanced-postback-configuration.html">Advanced Postback Configuration</a></li><li><strong>RECOMMENDED</strong> 👍 <a href="./testing-postbacks.html">Postback Testing</a></li></ul><p>Postback Testing makes it easy to verify if you have properly enabled a postback for an ad partner and (if applicable) if you have the correct ad partner credentials entered.</p><h2 id="_4-create-ad-link" tabindex="-1">4. Create Ad Link <a class="header-anchor" href="#_4-create-ad-link" aria-label="Permalink to &quot;4. Create Ad Link&quot;">​</a></h2><p>For non-SANs, they require <a href="./ad-links.html">Branch Ad Links</a> in their campaigns in order for Branch to properly attribute conversions.</p><p><a href="./ad-links.html">Create Ad Links</a></p><h2 id="_5-verify-data-sent" tabindex="-1">5. Verify Data Sent <a class="header-anchor" href="#_5-verify-data-sent" aria-label="Permalink to &quot;5. Verify Data Sent&quot;">​</a></h2><p>Once the above steps are complete, you are ready to start launching campaigns. Branch-attributed conversions enabled as postbacks will be sent to the winning ad network that drove the conversion.</p><h4 id="obtain-ad-partner-key" tabindex="-1">Obtain Ad Partner Key <a class="header-anchor" href="#obtain-ad-partner-key" aria-label="Permalink to &quot;Obtain Ad Partner Key&quot;">​</a></h4><p>You need to obtain your ad partner&#39;s <strong>$3p Value</strong>. You can find this in the <strong>Account Settings</strong> tab of your ad partner in the <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Partner Management page</strong></a>.</p><p>To verify data is being sent from Branch to the ad network, you can look at the Branch Dashboard&#39;s <a href="https://dashboard.branch.io/liveview/webhooks" target="_blank" rel="noreferrer">Liveview Webhook Records</a> and apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>ad partner (3p)</td><td>equals</td><td>Your ad partner key</td></tr></tbody></table><p>We also recommend adding the following columns to better understand the postback/webhook being sent:</p><ul><li><p>Webhook Response Code</p><ul><li>200 Codes: Success</li><li>400 Codes: Error</li></ul></li><li><p>IDFA/AAID &amp; Click ID: A good indicator that macros are being populated properly.</p></li></ul><div class="info custom-block"><p class="custom-block-title">Wait Period</p><p>Please be patient as data may take some time to flow through Branch&#39;s attribution systems and onto the ad networks. If data has not appeared in your ad network after 30 minutes of completing a test conversion, review the above steps to see if you may have missed something.</p></div>',28)])])}const b=a(o,[["render",i]]);export{u as __pageData,b as default};
